using System.Collections;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Interacção de um inimigo com puzzles (Enemy Creator — Etapa 6.2), baseada
/// nas flags de <see cref="EnemyData.weaknesses"/> (Etapa 1.1):
///
/// - canPressWeightPlate / stats.weight: consumido directamente por WeightPlate
///   (Etapa 6.1 — "peso necessário vs peso do inimigo").
/// - canActivateButton: consumido directamente por Switch (Etapa 6.1).
/// - canBePushed: consumido por EnemyHealth.ApplyKnockback e por habilidades
///   de empurrar do player ("pode ser empurrado para posição").
/// - canBeUsedAsPlatform: o inimigo deve ter um collider sólido; este
///   componente expõe a flag para as habilidades/checks do player.
/// - canBlockLaser: consumido por ProjectileController (projécteis e lasers
///   são bloqueados pelo inimigo-escudo, mesmo sem dano).
/// - canDestroyObjectsOnAttack: ataques deste inimigo destroem objectos
///   (IProjectileDestructible) e activam switches (IProjectileActivatable) —
///   os EnemyAttack chamam <see cref="ApplyAttackToObjects"/>.
/// - canHurtOtherEnemies / canTakeDamageFromOtherEnemyProjectiles: wiring em
///   ProjectileController ("pode ferir/ser destruído por outros inimigos").
///
/// "Necessário manter vivo para puzzle": se "requiredAliveForPuzzle" e o
/// inimigo morrer/desactivar, dispara "onPuzzleEnemyLost" e (opcional) faz um
/// respawn controlado após "respawnDelay" — via <see cref="ResetEnemy"/>,
/// também reutilizado pela Etapa 7.3.
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController))]
public class EnemyPuzzleInteraction : MonoBehaviour
{
    [Header("Necessário Para o Puzzle (Etapa 6.2)")]
    [Tooltip("Este inimigo tem de continuar vivo para o puzzle ser solúvel (ver também weaknesses.canBeUsedToSolvePuzzle).")]
    public bool requiredAliveForPuzzle = false;

    [Tooltip("Se o inimigo necessário morrer/desactivar, respawna automaticamente após 'respawnDelay' (reset controlado).")]
    public bool autoRespawnIfLost = true;

    [Min(0f)] public float respawnDelay = 2f;

    [Header("Eventos")]
    [Tooltip("Disparado quando um inimigo 'necessário para o puzzle' morre/desactiva (ex: mostrar aviso, resetar sala).")]
    public UnityEvent onPuzzleEnemyLost;

    private EnemyController _controller;
    private EnemyHealth _health;
    private EnemyDropTable _dropTable;
    private Coroutine _respawnRoutine;

    private EnemyWeaknessConfig Weaknesses => _controller.Data != null ? _controller.Data.weaknesses : null;

    // Atalhos de leitura para habilidades do player/outros sistemas.
    public bool CanBePushed => Weaknesses != null && Weaknesses.canBePushed;
    public bool CanBeUsedAsPlatform => Weaknesses != null && Weaknesses.canBeUsedAsPlatform;
    public bool CanBeUsedToSolvePuzzle => Weaknesses != null && Weaknesses.canBeUsedToSolvePuzzle;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
        _health = GetComponent<EnemyHealth>();
        _dropTable = GetComponent<EnemyDropTable>();
    }

    private void OnEnable()
    {
        _controller.OnStateChanged += HandleStateChanged;
    }

    private void OnDisable()
    {
        _controller.OnStateChanged -= HandleStateChanged;

        if (_respawnRoutine != null)
        {
            StopCoroutine(_respawnRoutine);
            _respawnRoutine = null;
        }
    }

    private void HandleStateChanged(EnemyState oldState, EnemyState newState)
    {
        if (!requiredAliveForPuzzle) return;
        if (newState != EnemyState.Morto && newState != EnemyState.Desactivado) return;

        onPuzzleEnemyLost?.Invoke();

        if (autoRespawnIfLost && _respawnRoutine == null)
            _respawnRoutine = StartCoroutine(RespawnRoutine());
    }

    private IEnumerator RespawnRoutine()
    {
        yield return new WaitForSeconds(respawnDelay);
        ResetEnemy();
        _respawnRoutine = null;
    }

    /// <summary>
    /// Reset/respawn controlado (Etapa 6.2; reutilizado pela Etapa 7.3): volta
    /// à HomePosition, repõe a vida, rearma os drops comuns e sai do estado
    /// terminal (ResetState → Idle). Nota: se uma condição de desactivação por
    /// variável global (Etapa 5.4) continuar verdadeira, o inimigo volta a
    /// desactivar-se imediatamente — comportamento desejado.
    /// </summary>
    public void ResetEnemy()
    {
        transform.position = _controller.HomePosition;

        if (_controller.Rb != null)
            _controller.Rb.velocity = Vector2.zero;

        if (_health != null) _health.ResetHealth();
        if (_dropTable != null) _dropTable.ResetDrops();

        _controller.Target = null;
        _controller.ResetState(EnemyState.Idle);
    }

    /// <summary>
    /// Aplica o efeito "destruir objectos / activar switches ao atacar" numa
    /// área (EnemyWeaknessConfig.canDestroyObjectsOnAttack). Os EnemyAttack
    /// de melee/investida podem chamar isto no momento do impacto:
    /// "ctx.Controller.GetEnemyComponent&lt;EnemyPuzzleInteraction&gt;()?.ApplyAttackToObjects(centro, raio)".
    /// </summary>
    public void ApplyAttackToObjects(Vector2 center, float radius)
    {
        var weaknesses = Weaknesses;
        if (weaknesses == null || !weaknesses.canDestroyObjectsOnAttack) return;

        var hits = Physics2D.OverlapCircleAll(center, radius);

        foreach (var hit in hits)
        {
            if (hit.gameObject == gameObject) continue;

            var destructible = hit.GetComponent<IProjectileDestructible>();
            if (destructible != null)
            {
                destructible.DestroyByProjectile(null); // null = destruído por ataque corpo-a-corpo
                continue;
            }

            var activatable = hit.GetComponent<IProjectileActivatable>();
            if (activatable != null)
                activatable.ActivateByProjectile(null);
        }
    }
}
